    let mid = (lo + hi) shr 1
    if cp < incbTable[mid].lo:
      hi = mid - 1
    elif cp > incbTable[mid].hi:
      lo = mid + 1
    else:
      return InCBKind(incbTable[mid].cls)
  return incbNone
